// ===== LẤY TOÀN BỘ ITEM INPUT =====
const data = $input.all();

// ✅ count = tổng số item input
const count = data.length;

// Thời gian hiện tại (chỉ lấy ngày)
const now = new Date();
now.setHours(0, 0, 0, 0);

// ===== XỬ LÝ FIFO =====
const processedData = data.map(item => {
  const json = item.json;

  let ngayNhapKho = json['import_date'] || json['Ngày_nhập_kho'];
  if (!ngayNhapKho) return null;

  let nhapKhoDate;

  if (typeof ngayNhapKho === 'string') {
    const trimmed = ngayNhapKho.trim();

    // YYYY-MM-DD
    if (/^\d{4}-\d{1,2}-\d{1,2}$/.test(trimmed)) {
      const [y, m, d] = trimmed.split('-');
      nhapKhoDate = new Date(+y, +m - 1, +d);
    }
    // DD/MM/YYYY hoặc DD/MM/YYYY HH:mm:ss
    else if (trimmed.includes('/')) {
      const [d, m, y] = trimmed.split(' ')[0].split('/');
      nhapKhoDate = new Date(+y, +m - 1, +d);
    } else {
      return null;
    }
  } else {
    nhapKhoDate = new Date(ngayNhapKho);
  }

  nhapKhoDate.setHours(0, 0, 0, 0);

  const diffMs = now - nhapKhoDate;
  const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

  return {
    ...json,
    diffMs,
    diffDays,
    count, // ✅ tổng số item input
    ngayNhapKhoFormatted: nhapKhoDate.toISOString().split('T')[0],
    serial: json['serial_number'] || json['So_Serial'] || json['Loại Serial'],
  };
}).filter(item => item && !isNaN(item.diffMs));

// ===== SORT FIFO (lâu nhất trước) =====
processedData.sort((a, b) => b.diffMs - a.diffMs);

// ===== RETURN =====
return processedData.map(item => ({
  json: item
}));

