const data = $input.all();

// ===== LỌC ITEM BIN KHÔNG CHỨA "cd." (case-sensitive) =====
const filteredData = data.filter(item => {
  const bin = item.json?.bin;
  return typeof bin === 'string' && !bin.includes('cd.');
});

// ===== NẾU TOÀN BỘ INPUT ĐỀU CHỨA "cd." =====
if (data.length > 0 && filteredData.length === 0) {
  return [
    {
      json: {
        message: 'cd only',
        count: data.length,
      },
    },
  ];
}

// ✅ count = tổng số item sau khi lọc
const count = filteredData.length;

// ===== PARSE NGÀY NHẬP =====
const parsedItems = filteredData.map(item => {
  const json = item.json;

  let ngayNhapKho = json['import_date'] || json['Ngày_nhập_kho'];
  if (!ngayNhapKho) return null;

  let nhapKhoDate;

  if (typeof ngayNhapKho === 'string') {
    const trimmed = ngayNhapKho.trim();

    // YYYY-MM-DD
    if (/^\d{4}-\d{1,2}-\d{1,2}$/.test(trimmed)) {
      const [y, m, d] = trimmed.split('-');
      nhapKhoDate = new Date(+y, +m - 1, +d);
    }
    // DD/MM/YYYY hoặc DD/MM/YYYY HH:mm:ss
    else if (trimmed.includes('/')) {
      const [d, m, y] = trimmed.split(' ')[0].split('/');
      nhapKhoDate = new Date(+y, +m - 1, +d);
    } else {
      return null;
    }
  } else {
    nhapKhoDate = new Date(ngayNhapKho);
  }

  nhapKhoDate.setHours(0, 0, 0, 0);

  return {
    ...json,
    nhapKhoDate,
    serial: json['serial_number'] || json['So_Serial'] || json['Loại Serial'],
  };
}).filter(Boolean);

// ===== TÌM NGÀY NHẬP CŨ NHẤT =====
const oldestDate = parsedItems.reduce(
  (min, item) => (item.nhapKhoDate < min ? item.nhapKhoDate : min),
  parsedItems[0].nhapKhoDate
);

// ===== TÍNH DIFFDAYS =====
const processedData = parsedItems.map(item => {
  const diffMs = item.nhapKhoDate - oldestDate;
  const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

  return {
    ...item,
    diffMs,
    diffDays,
    count,
    ngayNhapKhoFormatted: item.nhapKhoDate.toISOString().split('T')[0],
  };
});

// ===== SORT FIFO =====
processedData.sort((a, b) => a.diffDays - b.diffDays);

// ===== RETURN =====
return processedData.map(item => ({
  json: item,
}));

